(function($){$(".shortlinkspro-clicks-cleanup-button").on("click",function(e){e.preventDefault();var $this=$(this);var row=$this.closest('.cmb-row');var spinner=row.find('.spinner');var response_div=row.find('.shortlinkspro-clicks-cleanup-response');var id=$this.attr('id');$(".shortlinkspro-clicks-cleanup-button").attr('disabled',!0);spinner.addClass('is-active');response_div.fadeOut('fast');$.ajax({url:shortlinkspro_admin_tools.ajaxurl,method:'POST',data:{action:'shortlinkspro_clicks_cleanup',id:id,nonce:shortlinkspro_admin_tools.nonce,},success:function(response){$(".shortlinkspro-clicks-cleanup-button").attr('disabled',!1);spinner.removeClass('is-active');response_div.fadeIn('fast')},error:function(response){}})});$(".cmb2-id-import-from-plugin input[name=\"import_from_plugin\"]").on("change",function(e){var $this=$(this);var plugin=$this.val();var all_supports=['links','clicks','link_categories','link_tags'];var supports=$this.data(plugin).split(',');var not_supports=all_supports.filter(function(i){return supports.indexOf(i)<0});$('.cmb2-id-import-from-plugin-data').slideDown("fast");supports.forEach((item)=>{$(".cmb2-id-import-from-plugin-data input[value=\""+item+"\"]").parent().slideDown("fast")});not_supports.forEach((item)=>{$(".cmb2-id-import-from-plugin-data input[value=\""+item+"\"]").parent().slideUp("fast")})});$("#import_from_plugin_button").on("click",function(e){var $this=$(this);if($this.prop('disabled')){return}
var plugin=$('.cmb2-id-import-from-plugin input[name=\"import_from_plugin\"]:checked').val();var supports=$('.cmb2-id-import-from-plugin input[name=\"import_from_plugin\"]:checked').data(plugin);var row=$this.closest('.cmb-row');var spinner=row.find('.spinner');var response_div=row.find('.shortlinkspro-import-from-plugin-response');var error_div=row.find('.shortlinkspro-import-from-plugin-error');if(plugin===''){error_div.html(shortlinkspro_admin_tools.import_from_plugin_no_plugin_text);error_div.slideDown('fast');return}
var plugin_data='';$('.cmb2-id-import-from-plugin-data input[name=\"import_from_plugin_data[]\"]:checked').each(function(){if(supports.indexOf($(this).val())!==-1){plugin_data+=$(this).val()+','}});plugin_data=plugin_data.substring(0,plugin_data.length-1);if(plugin_data===''){error_div.html(shortlinkspro_admin_tools.import_from_plugin_no_data_text);error_div.slideDown('fast');return}
error_div.slideUp('fast');response_div.html(shortlinkspro_admin_tools.import_from_plugin_importing_text);response_div.slideDown('fast');spinner.addClass('is-active');$this.prop('disabled',!0);shortlinkspro_run_plugin_import_loop=0;shortlinkspro_plugin_import_group=0;shortlinkspro_run_plugin_import(plugin,plugin_data,$this,response_div,spinner)});var shortlinkspro_run_plugin_import_loop=0;var shortlinkspro_plugin_import_group=0;function shortlinkspro_run_plugin_import(plugin,plugin_data,button,response_div,spinner){var groups=plugin_data.split(',');if(groups[shortlinkspro_plugin_import_group]===undefined){spinner.removeClass('is-active');button.prop('disabled',!1);response_div.html(shortlinkspro_admin_tools.import_from_plugin_finished_text);return}
$.ajax({url:shortlinkspro_admin_tools.ajaxurl,method:'POST',data:{action:'shortlinkspro_import_from_plugin',nonce:shortlinkspro_admin_tools.nonce,plugin:plugin,group:groups[shortlinkspro_plugin_import_group],loop:shortlinkspro_run_plugin_import_loop,},success:function(response){if(response.data.message!==undefined){response_div.html(response.data.message)}
if(response.data.run_again!==undefined&&response.data.run_again){shortlinkspro_run_plugin_import_loop++;shortlinkspro_run_plugin_import(plugin,plugin_data,button,response_div,spinner)}else{shortlinkspro_plugin_import_group++;shortlinkspro_run_plugin_import_loop=0;setTimeout(function(){shortlinkspro_run_plugin_import(plugin,plugin_data,button,response_div,spinner)},500)}},error:function(response){}})}})(jQuery)